import 'app_novo:dio/dio.dart';

// Modelo para envelopar a resposta do Login de forma legível
class LoginResponse {
  final bool sucesso;
    final bool dispositivoAutorizado;
      final String? deviceId;
        final Map<String, dynamic>? dadosUsuario;

          LoginResponse({
              required this.sucesso,
                  required this.dispositivoAutorizado,
                      this.deviceId,
                          this.dadosUsuario,
                            });
                            }

                            class AuthRepository {
                              final Dio _dio = Dio();

                                // 1. Endpoint de Login
                                  Future<LoginResponse> tentarAutenticacao(String identificacao, String senha, String deviceId) async {
                                      // SIMULAÇÃO DE CHAMADA HTTP (Substituir pela URL real da sua API futuramente)
                                          await Future.delayed(const Duration(seconds: 1));

                                              // Cenário de Erro 1: Dados de login inválidos
                                                  if (identificacao == "erro") {
                                                        return LoginResponse(sucesso: false, dispositivoAutorizado: false);
                                                            }

                                                                // Cenário de Erro 2: Dados certos, mas o aparelho não está vinculado ao posto desse funcionário
                                                                    if (identificacao == "bloqueado") {
                                                                          return LoginResponse(
                                                                                  sucesso: true, 
                                                                                          dispositivoAutorizado: false, 
                                                                                                  deviceId: deviceId, // API devolve o ID para o app exibir na tela
                                                                                                        );
                                                                                                            }

                                                                                                                // Cenário de Sucesso Absoluto: Retorna o ID interno do banco e a Matrícula separados
                                                                                                                    return LoginResponse(
                                                                                                                          sucesso: true,
                                                                                                                                dispositivoAutorizado: true,
                                                                                                                                      dadosUsuario: {
                                                                                                                                              "id_banco": 742,
                                                                                                                                                      "matricula": "102030",
                                                                                                                                                              "funcionario": "Carlos Eduardo",
                                                                                                                                                                      "posto": "Portaria Central - Unidade 01",
                                                                                                                                                                              "hora_servidor": "14:52:10",
                                                                                                                                                                                      "exige_foto": true, // API dita se o posto exige foto ou não
                                                                                                                                                                                            },
                                                                                                                                                                                                );
                                                                                                                                                                                                  }

                                                                                                                                                                                                    // 2. Endpoint de Envio de Ponto (Multipart / Blob Binário)
                                                                                                                                                                                                      Future<bool> registrarPontoComBlob({
                                                                                                                                                                                                          required int idBanco,
                                                                                                                                                                                                              required String matricula,
                                                                                                                                                                                                                  required String deviceId,
                                                                                                                                                                                                                      required double latitude,
                                                                                                                                                                                                                          required double longitude,
                                                                                                                                                                                                                              required String timestamp,
                                                                                                                                                                                                                                  String? caminhoFotoLocal,
                                                                                                                                                                                                                                    }) async {
                                                                                                                                                                                                                                        try {
                                                                                                                                                                                                                                              // Monta os dados textuais do formulário
                                                                                                                                                                                                                                                    Map<String, dynamic> mapaFormulario = {
                                                                                                                                                                                                                                                            "id_banco": idBanco,
                                                                                                                                                                                                                                                                    "matricula": matricula,
                                                                                                                                                                                                                                                                            "device_id": deviceId,
                                                                                                                                                                                                                                                                                    "latitude": latitude,
                                                                                                                                                                                                                                                                                            "longitude": longitude,
                                                                                                                                                                                                                                                                                                    "timestamp": timestamp,
                                                                                                                                                                                                                                                                                                          };

                                                                                                                                                                                                                                                                                                                // Se o caminho da foto existir, anexa o arquivo binário puro (Blob) de forma leve
                                                                                                                                                                                                                                                                                                                      if (caminhoFotoLocal != null) {
                                                                                                                                                                                                                                                                                                                              mapaFormulario["foto"] = await MultipartFile.fromFile(
                                                                                                                                                                                                                                                                                                                                        caminhoFotoLocal,
                                                                                                                                                                                                                                                                                                                                                  filename: "ponto_${idBanco}_$timestamp.jpg",
                                                                                                                                                                                                                                                                                                                                                          );
                                                                                                                                                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                                                                                                                                                      FormData formData = FormData.fromMap(mapaFormulario);

                                                                                                                                                                                                                                                                                                                                                                            // Chamada HTTP real via POST HTTPS
                                                                                                                                                                                                                                                                                                                                                                                  // final response = await _dio.post("https://suaapi.com/api/bater-ponto", data: formData);
                                                                                                                                                                                                                                                                                                                                                                                        // return response.statusCode == 200;

                                                                                                                                                                                                                                                                                                                                                                                              await Future.delayed(const Duration(seconds: 2)); // Simula envio
                                                                                                                                                                                                                                                                                                                                                                                                    return true;
                                                                                                                                                                                                                                                                                                                                                                                                        } catch (e) {
                                                                                                                                                                                                                                                                                                                                                                                                              print("Erro ao transmitir ponto via Multipart: $e");
                                                                                                                                                                                                                                                                                                                                                                                                                    return false;
                                                                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                                                                          }
                                                                                                                                                                                                                                                                                                                                                                                                                          }


                                                                                                                                                                                                                                                                                                                                                                                                                          class AuthRepository {
                                                                                                                                                                                                                                                                                                                                                                                                                            final Dio _dio = Dio();
                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                // 1. CONFIGURE SUA URL AQUI (Centralizado)
                                                                                                                                                                                                                                                                                                                                                                                                                                  static const String _baseUrl = 'https://api.meusite.com/v1'; 

                                                                                                                                                                                                                                                                                                                                                                                                                                    // 1. Endpoint de Login
                                                                                                                                                                                                                                                                                                                                                                                                                                      Future<LoginResponse> tentarAutenticacao(String identificacao, String senha, String deviceId) async {
                                                                                                                                                                                                                                                                                                                                                                                                                                          try {
                                                                                                                                                                                                                                                                                                                                                                                                                                                // CHAMADA HTTP REAL: Substituindo a simulação pelo Dio
                                                                                                                                                                                                                                                                                                                                                                                                                                                      final response = await _dio.post(
                                                                                                                                                                                                                                                                                                                                                                                                                                                              '$_baseUrl/login', // Monta: https://api.meusite.com/v1/login
                                                                                                                                                                                                                                                                                                                                                                                                                                                                      data: {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                'identificacao': identificacao,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          'senha': senha,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    'device_id': deviceId,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  );

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        if (response.statusCode == 200) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                final dados = response.data; // Resposta que veio do seu servidor

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        // Aqui você trata as regras que a IA simulou, mas usando os dados da sua API:
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                return LoginResponse(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          sucesso: dados['sucesso'] ?? false,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    dispositivoAutorizado: dados['dispositivo_autorizado'] ?? false,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              deviceId: dados['device_id'],
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        dadosUsuario: dados['dados_usuario'],
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  return LoginResponse(sucesso: false, dispositivoAutorizado: false);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      } catch (e) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            print("Erro no login: $e");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  return LoginResponse(sucesso: false, dispositivoAutorizado: false);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          // 2. Endpoint de Envio de Ponto (Multipart / Blob Binário)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            Future<bool> registrarPontoComBlob({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                required int idBanco,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    required String matricula,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        required String deviceId,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            required double latitude,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                required double longitude,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    required String timestamp,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        String? caminhoFotoLocal,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          }) async {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              try {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    Map<String, dynamic> mapaFormulario = {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            "id_banco": idBanco,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    "matricula": matricula,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            "device_id": deviceId,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    "latitude": latitude,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            "longitude": longitude,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    "timestamp": timestamp,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          };

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                if (caminhoFotoLocal != null) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        mapaFormulario["foto"] = await MultipartFile.fromFile(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  caminhoFotoLocal,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            filename: "ponto_${idBanco}_$timestamp.jpg",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                FormData formData = FormData.fromMap(mapaFormulario);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      // CHAMADA HTTP REAL ATIVADA AQUI:
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            final response = await _dio.post(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    "$_baseUrl/bater-ponto", // Usa a nossa variável lá de cima
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            data: formData,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              return response.statusCode == 200;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  } catch (e) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        print("Erro ao transmitir ponto via Multipart: $e");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              return false;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }